import{_ as t,o as a,c as d,ai as r}from"./chunks/framework.Bke2s2V8.js";const b=JSON.parse('{"title":"Le Perfekt","description":"","frontmatter":{"prev":{"text":"Introduction Module 4","link":"/module-4-le-temps/"}},"headers":[],"relativePath":"module-4-le-temps/perfekt.md","filePath":"module-4-le-temps/perfekt.md","lastUpdated":1773298982000}'),s={name:"module-4-le-temps/perfekt.md"};function n(i,e,l,o,m,c){return a(),d("div",null,[...e[0]||(e[0]=[r('<h1 id="le-perfekt" tabindex="-1">Le Perfekt <a class="header-anchor" href="#le-perfekt" aria-label="Permalink to “Le Perfekt”">​</a></h1><p><strong>Prérequis :</strong> <a href="./../module-3-quotidien/verbes-modaux.html">Les verbes modaux</a></p><p><strong>Objectif :</strong> former et utiliser le Perfekt: le temps du passé a l&#39;oral en allemand.</p><p>Le Perfekt est le temps qu&#39;on utilisé pour parler du passé dans une conversation. Il correspond au passé composé français, mais sa logique de construction est différente.</p><h2 id="la-structure" tabindex="-1">La structure <a class="header-anchor" href="#la-structure" aria-label="Permalink to “La structure”">​</a></h2><p>Le Perfekt se compose de deux éléments : un <strong>auxiliaire conjugue en position 2</strong> et le <strong>participe passé en fin de phrase</strong>.</p><div class="mt-4 p-4 rounded-xl border border-gray-200"><div class="grid grid-cols-4 gap-2 text-center"><div class="bg-blue-50 border border-blue-200 rounded p-2"><div class="text-xs text-blue-500 font-medium">Sujet</div><div class="font-bold text-blue-800">Ich</div></div><div class="bg-green-50 border border-green-200 rounded p-2"><div class="text-xs text-green-500 font-medium">Auxiliaire (pos. 2)</div><div class="font-bold text-green-800">habe</div></div><div class="bg-gray-50 border border-gray-200 rounded p-2"><div class="text-xs text-gray-500 font-medium">Complement</div><div class="font-bold text-gray-700">ein Buch</div></div><div class="bg-orange-50 border border-orange-200 rounded p-2"><div class="text-xs text-orange-500 font-medium">Participe (fin)</div><div class="font-bold text-orange-800">gelesen.</div></div></div><div class="text-sm text-gray-500 text-center mt-3">J&#39;ai lu un livre.</div></div><h2 id="haben-ou-sein" tabindex="-1">haben ou sein ? <a class="header-anchor" href="#haben-ou-sein" aria-label="Permalink to “haben ou sein ?”">​</a></h2><p>C&#39;est le choix central du Perfekt.</p><div class="mt-4 grid gap-3"><div class="p-4 rounded-xl border border-green-200 bg-green-50"><div class="font-bold text-green-800 text-lg">haben</div><div class="text-sm text-green-700 mt-1">La majorité des verbes - tout ce qui exprime une action sans déplacement, et les verbes transitifs (avec objet direct).</div><div class="mt-2 grid gap-1 text-sm text-gray-600"><div><em>Ich habe gegessen.</em> - J&#39;ai mange.</div><div><em>Er hat gearbeitet.</em> - Il a travaillé.</div><div><em>Wir haben das Buch gelesen.</em> - Nous avons lu le livre.</div></div></div><div class="p-4 rounded-xl border border-blue-200 bg-blue-50"><div class="font-bold text-blue-800 text-lg">sein</div><div class="text-sm text-blue-700 mt-1">Les verbes de déplacement (d&#39;un endroit a un autre), les verbes de changement d&#39;etat, et les verbes <em>sein</em>, <em>bleiben</em>, <em>werden</em>, <em>passieren</em>.</div><div class="mt-2 grid gap-1 text-sm text-gray-600"><div><em>Ich bin gegangen.</em> - Je suis alle(e).</div><div><em>Er ist aufgestanden.</em> - Il s&#39;est leve.</div><div><em>Sie ist eingeschlafen.</em> - Elle s&#39;est endormie.</div></div></div></div><div class="tip custom-block"><p class="custom-block-title">L&#39;astuce du COD</p><p>Si le verbe peut avoir un complément d&#39;objet direct (accusatif), c&#39;est presque toujours <em>haben</em>. <em>Fahren</em> (conduire) avec un COD : <em>Er hat das Auto gefahren</em> (haben). <em>Fahren</em> sans COD, déplacement : <em>Er ist nach Berlin gefahren</em> (sein). Le même verbe peut changer d&#39;auxiliaire selon le sens.</p></div><h2 id="exemples-courants" tabindex="-1">Exemples courants <a class="header-anchor" href="#exemples-courants" aria-label="Permalink to “Exemples courants”">​</a></h2><table tabindex="0"><thead><tr><th>Infinitif</th><th>Participe</th><th>Auxiliaire</th><th>Exemple</th></tr></thead><tbody><tr><td>machen</td><td>gemacht</td><td>haben</td><td><em>Ich habe Hausaufgaben gemacht.</em></td></tr><tr><td>kaufen</td><td>gekauft</td><td>haben</td><td><em>Er hat ein Ticket gekauft.</em></td></tr><tr><td>trinken</td><td>getrunken</td><td>haben</td><td><em>Wir haben Kaffee getrunken.</em></td></tr><tr><td>sehen</td><td>gesehen</td><td>haben</td><td><em>Ich habe den Film gesehen.</em></td></tr><tr><td>gehen</td><td>gegangen</td><td>sein</td><td><em>Sie ist nach Hause gegangen.</em></td></tr><tr><td>kommen</td><td>gekommen</td><td>sein</td><td><em>Er ist spat gekommen.</em></td></tr><tr><td>fahren</td><td>gefahren</td><td>sein</td><td><em>Wir sind nach Paris gefahren.</em></td></tr><tr><td>bleiben</td><td>geblieben</td><td>sein</td><td><em>Du bist zu Hause geblieben.</em></td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Le participe passé ne s&#39;accorde pas</p><p>Contrairement au français, le participe passé allemand est invariable: il ne s&#39;accorde ni en genre ni en nombre. <em>Ich habe gegessen</em>, <em>Sie hat gegessen</em>, <em>Wir haben gegessen</em> : la forme <em>gegessen</em> ne change jamais.</p></div>',14)])])}const g=t(s,[["render",n]]);export{b as __pageData,g as default};
